template<typename T>
void verify(const T* cpu_out, const T* gpu_out, int64_t n)
{
  int error = memcmp(cpu_out, gpu_out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (cpu_out[i] != gpu_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)cpu_out[i], (double)gpu_out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
void scan_bcao_kernel(
  const int64_t nblocks,
  T *g_odata,
  const T *g_idata)
{
  T temp[2*N];

  #pragma omp parallel for
  for (int64_t bid = 0; bid < nblocks; bid++)
  {
    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    int thid = 0; 
    // Simulate thread loop for single thread per block logic in OpenMP context
    // Since OpenMP parallel for distributes blocks, each thread handles one block fully
    // We must simulate the intra-block threading manually or restructure.
    // However, the original CUDA code uses N/2 threads per block.
    // To preserve algorithm exactly, we need to simulate the thread interactions within the block.
    // Given OpenMP's model, we will use a local array and simulate the thread steps sequentially 
    // but logically parallel using omp parallel sections or just sequential simulation of the algorithm 
    // since the block size is small and fixed per iteration.

    // Actually, to truly parallelize within the block using OpenMP, we'd need nested parallelism 
    // or a different mapping. But the simplest correct translation that preserves the algorithm 
    // on CPU is to run the block logic sequentially per block (since blocks are independent) 
    // OR use a team of threads for each block. 
    // Given the constraints and typical OpenMP usage, we'll map each block to one thread 
    // and execute the intra-block logic sequentially (which is functionally equivalent for correctness).
    // If performance scaling within block is required, a more complex nested approach is needed.
    // For correctness and simplicity matching the "algorithm preservation":

    // Re-implementing the block logic sequentially for the assigned block 'bid'
    int local_temp[2*N]; // Use int for indices, T for values

    // Load data
    for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = a + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        local_temp[a + oa] = gi[a];
        local_temp[b + ob] = gi[b];
    }

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      if (d > 0) {
        for (int thid_inner = 0; thid_inner < d; thid_inner++)
        {
          int ai = offset*(2*thid_inner+1)-1;
          int bi = offset*(2*thid_inner+2)-1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          local_temp[bi] += local_temp[ai];
        }
      }
      offset *= 2;
    }

    local_temp[N-1+OFFSET(N-1)] = 0; 

    for (int d = 1; d < N; d *= 2) 
    {
      offset >>= 1;
      for (int thid_inner = 0; thid_inner < d; thid_inner++)
      {
        int ai = offset*(2*thid_inner+1)-1;
        int bi = offset*(2*thid_inner+2)-1;
        ai += OFFSET(ai);
        bi += OFFSET(bi);
        T t = local_temp[ai];
        local_temp[ai] = local_temp[bi];
        local_temp[bi] += t;
      }
    }

    for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = a + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        go[a] = local_temp[a + oa];
        go[b] = local_temp[b + ob];
    }
  }
}

template<typename T, int N>
void scan_kernel(
  const int64_t nblocks,
  T *g_odata,
  const T *g_idata)
{
  #pragma omp parallel for
  for (int64_t bid = 0; bid < nblocks; bid++)
  {
    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    T temp[N];

    // Load
    for (int t = 0; t < N/2; t++) {
        temp[2*t]   = gi[2*t];
        temp[2*t+1] = gi[2*t+1];
    }

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      for (int thid_inner = 0; thid_inner < d; thid_inner++)
      {
        int ai = offset*(2*thid_inner+1)-1;
        int bi = offset*(2*thid_inner+2)-1;
        temp[bi] += temp[ai];
      }
      offset *= 2;
    }

    temp[N-1] = 0; 

    for (int d = 1; d < N; d *= 2) 
    {
      offset >>= 1;
      for (int thid_inner = 0; thid_inner < d; thid_inner++)
      {
        int ai = offset*(2*thid_inner+1)-1;
        int bi = offset*(2*thid_inner+2)-1;
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }

    for (int t = 0; t < N/2; t++) {
        go[2*t]   = temp[2*t];
        go[2*t+1] = temp[2*t+1];
    }
  }
}

template <typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;

  int64_t nelems = num_blocks * N; 

  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *cpu_out = (T*) malloc (bytes);
  T *gpu_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t idx = 0; idx < nelems; idx++) in[idx] = rand() % 5 + 1;

  T *t_in = in;
  T *t_out = cpu_out;
  for (int64_t nb = 0; nb < num_blocks; nb++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  T *d_in = in; 
  T *d_out = (T*) malloc(bytes);

  // Determine thread count equivalent to CUDA grids
  int max_threads = omp_get_max_threads();
  // CUDA used 16 * multiProcessorCount. We'll just use available threads or a fixed large number
  // For simulation, we rely on omp parallel for to distribute blocks.

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scan<T, N>(num_blocks, d_out, d_in);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }
  memcpy(gpu_out, d_out, bytes);
  if (!timing) verify(cpu_out, gpu_out, nelems);


  start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scan_bcao<T, N>(num_blocks, d_out, d_in);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }
  memcpy(gpu_out, d_out, bytes);
  if (!timing) verify(cpu_out, gpu_out, nelems);

  free(d_out);
  free(in);
  free(cpu_out);
  free(gpu_out);
}

template<int N>
void run (const int64_t n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int64_t n = atol(argv[1]);
  const int repeat = atoi(argv[2]);

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}
